pub struct RagPipeline {
    retriever: Arc<dyn Retriever>,
    augmenter: Arc<dyn Augmenter>,
    generator: Option<Arc<dyn GenerationEngine>>,
    config: RagConfig,
}
impl RagPipeline {
    /// Create a new pipeline with the given stages and config.
    pub fn new(
        retriever: Arc<dyn Retriever>,
        augmenter: Arc<dyn Augmenter>,
        generator: Option<Arc<dyn GenerationEngine>>,
        config: RagConfig,
    ) -> Self {
        Self {
            retriever,
            augmenter,
            generator,
            config,
        }
    }

    /// Access the generation engine (if configured).
    pub fn generator(&self) -> Option<&Arc<dyn GenerationEngine>> {
        self.generator.as_ref()
    }

    /// Get the name of the active retriever (for config verification / tests).
    pub fn retriever_name(&self) -> &str {
        self.retriever.name()
    }

    /// Context-only mode: retrieve + augment, no generation.
    #[tracing::instrument(name = "corvia.rag.context", skip(self, query, opts), fields(scope_id))]
    pub async fn context(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
    ) -> Result<RagResponse> {
        self.run_pipeline(query, scope_id, opts, false).await
    }

    /// Context-only mode with a caller-specified token budget override.
    /// Used when MCP clients pass `max_tokens` to control context size.
    #[tracing::instrument(name = "corvia.rag.context_override", skip(self, query, opts), fields(scope_id))]
    pub async fn context_with_token_override(
        &self,
        query: &str,
        scope_id: &str,
        opts: Option<RetrievalOpts>,
        max_tokens: usize,
    ) -> Result<RagResponse> {
        self.run_pipeline_with_budget(query, scope_id, opts, false, Some(max_tokens)).await
    }
